  currentPage++;
  try {
    const response = await fetch(`/api/jobs?page=${currentPage}&limit=20`); // Example API call
    if (!response.ok) throw new Error('Failed to fetch jobs');
    const newJobs = await response.json();

    if (newJobs.length === 0) {
      loadMoreButton.style.display = 'none'; // No more jobs
