@ratelimit(key='ip', rate='5/m', block=True) # 5 attempts per minute per IP
@ratelimit(key='post:username_or_email', rate='3/h', block=True) # 3 attempts per username/email per hour
def login_view(request):
    if request.method == 'POST':
        recaptcha_response = request.POST.get('g-recaptcha-response')
        if not recaptcha_response:
            return JsonResponse({'error': 'Please complete the CAPTCHA.'}, status=400)

        captcha_verify_url = 'https://www.google.com/recaptcha/api/siteverify'
        captcha_data = {
            'secret': settings.RECAPTCHA_SECRET_KEY,
            'response': recaptcha_response,
            'remoteip': request.META.get('REMOTE_ADDR')
        }
        r = requests.post(captcha_verify_url, data=captcha_data)
        result = r.json()

        if not result.get('success'):
            return JsonResponse({'error': 'CAPTCHA verification failed. Please try again.'}, status=400)

        username = request.POST.get('username')
        password = request.POST.get('password')
        user = authenticate(request, username=username, password=password)

        if user is not None:
            login(request, user)
            return JsonResponse({'message': 'Login successful'}, status=200)
        else:
            # Return generic error message (see separate recommendation)
            return JsonResponse({'error': 'Invalid username or password provided.'}, status=400)
    return JsonResponse({'error': 'Only POST requests are allowed.'}, status=405)


